import React from 'react';
import { Card, CardContent, Box, Typography, Stack, IconButton } from '@mui/material';
import { PlayArrow, Pause } from '@mui/icons-material';
import response from './response.json';

interface CurrentTrack {
  title: string;
  artist: string;
  album: string;
  duration: string;
  elapsed: string;
}

interface Controls {
  isPlaying: boolean;
  volume: number;
}

interface MusicPlayerData {
  currentTrack: CurrentTrack;
  controls: Controls;
}

export default function Widget() {
  const data = response.data as MusicPlayerData;
  const { currentTrack, controls } = data;
  const { theme, primaryColor, accentColor } = response.meta;

  return (
    <Card sx={{ width: 'fit-content', minWidth: 320, maxWidth: 400, bgcolor: theme === 'dark' ? '#191414' : '#FFFFFF' }} elevation={2}>
      <CardContent sx={{ p: 2.5 }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="h6" sx={{ color: primaryColor }}>
              {currentTrack.title}
            </Typography>
            <Typography variant="body2" color="text.secondary">
              {currentTrack.artist} - {currentTrack.album}
            </Typography>
          </Box>

          <Stack direction="row" alignItems="center" spacing={2}>
            <IconButton>
              {controls.isPlaying ? (
                <Pause sx={{ color: primaryColor }} />
              ) : (
                <PlayArrow sx={{ color: primaryColor }} />
              )}
            </IconButton>
            <Box sx={{ flexGrow: 1 }}>
              <Typography variant="caption" color="text.secondary">
                {currentTrack.elapsed} / {currentTrack.duration}
              </Typography>
            </Box>
          </Stack>

          <Box sx={{ bgcolor: accentColor, padding: 1, borderRadius: 1 }}>
            <Typography variant="body2" color="text.secondary">
              Volume: {controls.volume}%
            </Typography>
          </Box>
        </Stack>
      </CardContent>
    </Card>
  );
}
